"use strict";(self.webpackChunkroadmap_sy=self.webpackChunkroadmap_sy||[]).push([[567],{5226:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Getting Started","href":"/","docId":"getting-started","unlisted":false},{"type":"category","label":"Core Skills","items":[{"type":"link","label":"Web","href":"/web","docId":"web","unlisted":false},{"type":"link","label":"Git","href":"/git","docId":"git","unlisted":false},{"type":"link","label":"Testing","href":"/testing","docId":"testing","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Deployment & Production","items":[{"type":"link","label":"Containerization","href":"/containerization","docId":"containerization","unlisted":false},{"type":"link","label":"CI/CD","href":"/ci-cd","docId":"ci-cd","unlisted":false},{"type":"link","label":"Observability","href":"/observability","docId":"observability","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Learning by Doing","items":[{"type":"link","label":"Open Source","href":"/open-source","docId":"open-source","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Learning from Others","items":[{"type":"link","label":"Mentorship","href":"/mentorship","docId":"mentorship","unlisted":false},{"type":"link","label":"Global Communities","href":"/global-communities","docId":"global-communities","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"ci-cd":{"id":"ci-cd","title":"CI/CD","description":"You\u2019ve merged your pull request, tests are green, and everything looks good locally. Time to relax and move on? Not quite. In modern development, merging code is just the start. Your changes now enter the CI/CD pipeline\u2014a set of automated steps that move code from your machine to production. Teams expect more than clean code; they expect you to understand and take ownership of the full lifecycle. CI/CD isn\u2019t just jargon\u2014it\u2019s the core engine of DevOps, enabling fast, reliable delivery through automation and best practices.","sidebar":"tutorialSidebar"},"containerization":{"id":"containerization","title":"Containerization","description":"Your new feature is complete. It runs flawlessly on your machine\u2014the logic is sound, the UI is polished. You ship it to the staging server, feeling confident. Then the bug report arrives: \\"App is crashing on launch.\\" You check the logs and find a cryptic error about a missing system dependency. The server environment is different from yours. Again.","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"What is xxx?","sidebar":"tutorialSidebar"},"git":{"id":"git","title":"Git","description":"You\'ve written some great code and saved the file. Maybe you even zipped the project folder and named it project-final-v2-really-final.zip as a backup. Your work is safe and you\'re ready to share it with the team, right? Not quite. That old habit of manually managing versions is a recipe for confusion and lost work in any professional team.","sidebar":"tutorialSidebar"},"global-communities":{"id":"global-communities","title":"Global Communities","description":"Building a successful tech career is not just about your technical skills\u2014it\'s about connecting with the right communities that can guide you, support you, and open doors to opportunities you might never find on your own. By joining global tech communities, you gain access to resources that can help you grow professionally, find international opportunities, and connect with others who share similar experiences and ambitions.","sidebar":"tutorialSidebar"},"mentorship":{"id":"mentorship","title":"Mentorship","description":"You have worked hard on tutorials, built your own projects, and maybe even got your first job as a developer. But sometimes you face problems that are very hard to solve by yourself. Maybe you are confused about how to make big decisions in your code, how to grow in your career, or what to learn next. Having someone with more experience to guide you can really help. In today\'s fast-changing tech world, having a mentor is not just useful\u2014it can be the difference between growing as a developer or feeling stuck and alone.","sidebar":"tutorialSidebar"},"observability":{"id":"observability","title":"Observability","description":"In modern software development, you don\u2019t just build an application and hope it runs smoothly. You need to understand its internal state and behavior from the outside, across the entire stack\u2014from a user\'s tap on a mobile screen to the deepest database query. This is observability. It\u2019s not just about watching for errors (that\u2019s monitoring); it\u2019s about being able to ask questions about your system to understand why things are happening, especially in complex, distributed environments.","sidebar":"tutorialSidebar"},"open-source":{"id":"open-source","title":"Open Source","description":"Contributing to open source is one of the best ways to grow as a developer, build your reputation, and connect with developers around the world. Open source gives you a way to show your skills to international employers and build professional relationships across borders.","sidebar":"tutorialSidebar"},"testing":{"id":"testing","title":"Testing","description":"You\u2019ve implemented the feature and tested it manually. Now you\u2019re ready to move on to the next task\u2014right? Not quite. The old idea of a developer writing code and tossing it over to QA is outdated. In today\u2019s agile environments, you\'re expected to be the first and most important line of defense for code quality. It\u2019s no longer enough for your code to \\"just work on your machine.\\" To grow as a developer, you need to treat testing as a core part of your workflow\u2014not an afterthought. Here\u2019s what modern teams typically expect from you when it comes to testing.","sidebar":"tutorialSidebar"},"web":{"id":"web","title":"Web","description":"Why it matters","sidebar":"tutorialSidebar"}}}}')}}]);